import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';

const BallyGamboyGame = () => {
    const gameRef = useRef(null);
    let player;

    useEffect(() => {
        const initializeGame = () => {
            const config = {
                type: Phaser.AUTO,
                width: 800,
                height: 600,
                scene: {
                    preload: preload,
                    create: create
                },
                physics: {
                    default: 'arcade',
                    arcade: {
                        gravity: { y: 0 },
                        debug: false
                    }
                }
            };

            gameRef.current = new Phaser.Game(config);
        };

        function preload() {
            this.load.image('player', './phaser-resources/images/champion.png');
            this.load.image('background', './phaser-resources/images/background.png');
        }

        function create() {
            const background = this.add.sprite(0, 0, 'background').setOrigin(0);
            background.displayWidth = this.sys.game.config.width;
            background.displayHeight = this.sys.game.config.height;

            player = this.physics.add.sprite(50, 225, 'player');
            player.setCollideWorldBounds(true);

            const tweens = this.tweens;
            this.input.on('pointerdown', function (pointer) {
                tweens.add({
                    targets: player,
                    x: pointer.x,
                    y: pointer.y,
                    duration: 500,
                    ease: 'Linear',
                });
            });
        }

        initializeGame();

        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
            }
        };
    }, []);

    return <div id="ballygamboy-game-container"></div>;
};

export default BallyGamboyGame;
